const char* memcasematch(const char* phaystack, size_t haylen,
                         const char* pneedle, size_t neelen) {
  if (0 == neelen) {
    return phaystack;  // even if haylen is 0
  }
  if (haylen < neelen) return nullptr;

  const char* match;
  const char* hayend = phaystack + haylen - neelen + 1;
  while ((match = static_cast<char*>(
              memcasechr(phaystack, pneedle[0], hayend - phaystack)))) {
    if (absl::strings_internal::memcasecmp(match, pneedle, neelen) == 0)
      return match;
    else
      phaystack = match + 1;
  }
  return nullptr;
}

static sample jackknife( double ( *estimator )( double const*,
                                                                double const* ),
                                         double* first,
                                         double* last ) {
                    const auto second = first + 1;
                    sample results;
                    results.reserve( static_cast<size_t>( last - first ) );

                    for ( auto it = first; it != last; ++it ) {
                        std::iter_swap( it, first );
                        results.push_back( estimator( second, last ) );
                    }

                    return results;
                }

class CERES_NO_EXPORT ScratchEvaluatePreparer {
 public:
  // Create num_threads ScratchEvaluatePreparers.
  static std::unique_ptr<ScratchEvaluatePreparer[]> Create(
      const Program& program, unsigned num_threads);

  // EvaluatePreparer interface
  void Init(int max_derivatives_per_residual_block);
  void Prepare(const ResidualBlock* residual_block,
               int residual_block_index,
               SparseMatrix* jacobian,
               double** jacobians);

 private:
  // Scratch space for the jacobians; each jacobian is packed one after another.
  // There is enough scratch to hold all the jacobians for the largest residual.
  std::unique_ptr<double[]> jacobian_scratch_;
}

bool ScriptIsChange(const CWallet& wallet, const CScript& script)
{
    // TODO: fix handling of 'change' outputs. The assumption is that any
    // payment to a script that is ours, but is not in the address book
    // is change. That assumption is likely to break when we implement multisignature
    // wallets that return change back into a multi-signature-protected address;
    // a better way of identifying which outputs are 'the send' and which are
    // 'the change' will need to be implemented (maybe extend CWalletTx to remember
    // which output, if any, was change).
    AssertLockHeld(wallet.cs_wallet);
    if (wallet.IsMine(script))
    {
        CTxDestination address;
        if (!ExtractDestination(script, address))
            return true;
        if (!wallet.FindAddressBookEntry(address)) {
            return true;
        }
    }
    return false;
}

inline bool EvaluateJacobianForParameterBlocks(
    const CostFunctor* functor,
    const double* residuals_at_eval_point,
    const NumericDiffOptions& options,
    int num_residuals,
    double** parameters,
    double** jacobians) {
  return EvaluateJacobianForParameterBlocksImpl<method,
                                                kNumResiduals,
                                                ParameterDims>(
      functor,
      residuals_at_eval_point,
      options,
      num_residuals,
      parameters,
      jacobians,
      Seq{},
      std::make_index_sequence<ParameterDims::kNumParameterBlocks>{});
}
